import React, { useState } from 'react';
import { Mail, Clock, Users, CheckCircle } from 'lucide-react';
import { useApp, useAppActions } from '../context/AppContext';
import { MessageItem } from '../types';
import '../styles/globals.css';

interface MessageCardProps {
  item: MessageItem;
  isAnySelected: boolean;
}

const MessageCard: React.FC<MessageCardProps> = ({ item, isAnySelected }) => {
  const { state } = useApp();
  const { toggleItemSelection } = useAppActions();

  const [isHovered, setIsHovered] = useState(false);
  const isSelected = state.selectedItems.includes(item.id);

  const showCheckbox = isAnySelected || isHovered;

  const handleClick = () => {
    if (showCheckbox) {
      toggleItemSelection(item.id);
    }
  };

  const getInitials = (name: string) => {
    return name
      .split(' ')
      .map(word => word[0])
      .join('')
      .toUpperCase()
      .slice(0, 2);
  };

  const isRead = item.subject.includes('[LIDO]');

  return (
    <div 
      className={`group cursor-pointer transition-all duration-200 animate-fade-in ${
        isSelected ? 'bg-blue-50 dark:bg-blue-900/20' : 'hover:bg-gray-50 dark:hover:bg-gray-800/50'
      }`}
      style={{
        backgroundColor: isSelected 
          ? 'var(--color-primary)10' 
          : isHovered 
            ? 'var(--color-surface)' 
            : 'transparent'
      }}
      onMouseEnter={() => setIsHovered(true)}
      onMouseLeave={() => setIsHovered(false)}
      onClick={handleClick}
    >
      <div className="p-4 flex items-center gap-3">
        {/* Checkbox ou Avatar */}
        <div className="flex-shrink-0 w-10 h-10 flex items-center justify-center">
          {showCheckbox ? (
            <input
              type="checkbox"
              checked={isSelected}
              onChange={() => {}} // Controlado pelo clique no card
              className="checkbox"
              onClick={(e) => e.stopPropagation()}
            />
          ) : (
            <div className="avatar avatar-sm">
              {getInitials(item.owner)}
            </div>
          )}
        </div>

        {/* Ícone de status */}
        <div className="flex-shrink-0">
          {isRead ? (
            <CheckCircle 
              size={16} 
              style={{ color: 'var(--color-success)' }}
            />
          ) : (
            <Mail 
              size={16} 
              style={{ color: 'var(--color-text-muted)' }}
            />
          )}
        </div>

        {/* Conteúdo principal */}
        <div className="flex-1 min-w-0">
          <div className="flex items-center gap-2 mb-1">
            <span 
              className={`font-medium truncate ${
                !isRead ? 'font-semibold' : ''
              }`}
              style={{ 
                color: isRead 
                  ? 'var(--color-text-secondary)' 
                  : 'var(--color-text-primary)' 
              }}
            >
              {item.owner}
            </span>
            {item.users && item.users.length > 0 && (
              <div className="flex items-center gap-1">
                <Users size={12} style={{ color: 'var(--color-text-muted)' }} />
                <span 
                  className="text-xs"
                  style={{ color: 'var(--color-text-muted)' }}
                >
                  {item.users.length}
                </span>
              </div>
            )}
          </div>

          <div className="truncate">
            <span 
              className={`text-sm ${
                !isRead ? 'font-medium' : ''
              }`}
              style={{ 
                color: isRead 
                  ? 'var(--color-text-secondary)' 
                  : 'var(--color-text-primary)' 
              }}
            >
              {item.subject}
            </span>
          </div>

          <div className="flex items-center gap-2 mt-1">
            <span 
              className="text-xs truncate"
              style={{ color: 'var(--color-text-muted)' }}
            >
              {item.name}
            </span>
            {item.time && (
              <div className="flex items-center gap-1">
                <Clock size={10} style={{ color: 'var(--color-text-muted)' }} />
                <span 
                  className="text-xs"
                  style={{ color: 'var(--color-text-muted)' }}
                >
                  {item.time}
                </span>
              </div>
            )}
          </div>
        </div>

        {/* Data/Hora no lado direito */}
        {item.date && (
          <div 
            className="flex-shrink-0 text-xs text-right"
            style={{ color: 'var(--color-text-muted)' }}
          >
            {item.date}
          </div>
        )}
      </div>
    </div>
  );
};

export default MessageCard;
